/**
 * tpch_validate.ts — SF=1 answer comparator used by the `validate_answers`
 * step in tx.ts. The answers ship as `workloads/tpch/answers_sf1.json`,
 * generated by `cmd/tpch-answers` from the upstream `.ans` reference files.
 *
 * Tolerances follow TPC-H spec §2.1.3.5 (numeric rounding): string values
 * compare exact, integer counts compare exact, float / numeric values
 * compare within ±1% or ±$100 (whichever is looser). The comparator is
 * best-effort and logs deltas instead of throwing, because the simplified
 * generation in tx.ts (random ASCII comments, uniform nation draws) will
 * drift answer magnitudes by more than the spec tolerance. The real
 * usefulness here is framework proof: queries parse, execute, and return
 * type-shaped rows.
 */
import type { SqlQuery } from "./helpers.ts";
import { ENV } from "./helpers.ts";

/** Answer payload shape — mirrors `cmd/tpch-answers` JSON output. */
export interface AnswerBlock {
  columns: string[];
  rows: string[][];
}

/** Top-level shape of answers_sf1.json. */
export interface AnswersFile {
  version: string;
  source: string;
  answers: Record<string, AnswerBlock>;
}

/** Per-query comparison result. */
export interface QueryCompareResult {
  query: string;
  status: "ok" | "skipped" | "mismatch" | "error";
  gotRows: number;
  wantRows: number;
  deltas: string[];
  errorMessage?: string;
}

/** Mixed value shape returned by the driver's queryRows helper. */
type DbCell = string | number | bigint | boolean | null | Date | undefined;

/**
 * Normalize a DB value to a comparison-friendly string. Dates serialize
 * via ISO, booleans via "t"/"f" (matches pg psql default), numbers keep
 * their native representation, null renders as "".
 */
function normalizeCell(v: DbCell): string {
  if (v === null || v === undefined) return "";
  if (typeof v === "string") return v.trim();
  if (typeof v === "boolean") return v ? "t" : "f";
  if (typeof v === "bigint") return v.toString();
  if (typeof v === "number") return Number.isFinite(v) ? String(v) : "";
  if (v instanceof Date) return v.toISOString().slice(0, 10);
  /* eslint-disable-next-line @typescript-eslint/no-base-to-string */
  return String(v);
}

const TOLERANCE_REL = 0.01; // ±1%
const TOLERANCE_ABS = 100; // ±$100

/**
 * Numeric-aware cell comparator. Both arms may be integer, decimal, or
 * a pre-stringified float. The tolerance only fires when BOTH sides
 * parse as numbers — otherwise we fall back to exact string compare.
 */
function cellsMatch(got: string, want: string): boolean {
  if (got === want) return true;
  const gN = parseFloat(got);
  const wN = parseFloat(want);
  if (!Number.isFinite(gN) || !Number.isFinite(wN)) return false;
  const absDelta = Math.abs(gN - wN);
  if (absDelta <= TOLERANCE_ABS) return true;
  const denom = Math.max(Math.abs(wN), 1);
  return absDelta / denom <= TOLERANCE_REL;
}

/**
 * Compare one query's result set row-by-row against the reference answer.
 * Returns a structured delta summary so the caller can log or aggregate.
 */
export function compareQueryResult(
  query: string,
  gotRows: DbCell[][],
  want: AnswerBlock,
): QueryCompareResult {
  const deltas: string[] = [];
  const rowBudget = Math.max(gotRows.length, want.rows.length);
  for (let i = 0; i < rowBudget; i++) {
    const got = gotRows[i];
    const w = want.rows[i];
    if (!got) {
      deltas.push(`row ${i}: missing, want=${JSON.stringify(w)}`);
      continue;
    }
    if (!w) {
      deltas.push(`row ${i}: extra, got=${JSON.stringify(got.map(normalizeCell))}`);
      continue;
    }
    const colBudget = Math.max(got.length, w.length);
    for (let c = 0; c < colBudget; c++) {
      const g = normalizeCell(got[c] as DbCell);
      const ww = (w[c] ?? "").trim();
      if (!cellsMatch(g, ww)) {
        deltas.push(`row ${i} col ${c}: got=${g} want=${ww}`);
      }
    }
  }
  return {
    query,
    status: deltas.length === 0 ? "ok" : "mismatch",
    gotRows: gotRows.length,
    wantRows: want.rows.length,
    deltas,
  };
}

/**
 * Shape of the minimal driver surface this module needs. Keeps the file
 * independent of the concrete `DriverX` class and lets callers pass a
 * transaction-scoped wrapper if they prefer.
 */
export interface AnswerRunner {
  queryRows(sql: SqlQuery, args?: Record<string, unknown>, limit?: number): DbCell[][];
}

/**
 * Drive all 22 queries through the runner, compare against `answers`,
 * and log one line per query. The object returned bundles every per-
 * query compare result so the caller can summarize.
 *
 * Params are a flat name→value map keyed as in the SQL file (:date,
 * :segment, ...). Callers pass a spec-frozen default set; this module
 * has no opinion on which values to pick.
 */
export function runAndCompareAllQueries(
  runner: AnswerRunner,
  queries: Record<string, SqlQuery | undefined>,
  params: Record<string, Record<string, unknown>>,
  answers: AnswersFile,
): QueryCompareResult[] {
  const results: QueryCompareResult[] = [];
  const ordered = Array.from({ length: 22 }, (_, i) => "q" + String(i + 1));
  const QUERY_TIMEOUT_WARN_MS = Number(
    ENV("TPCH_QUERY_WARN_MS", 60_000, "Warn when a query exceeds this many ms"),
  );
  for (const name of ordered) {
    const want = answers.answers[name];
    const sql = queries[name];
    if (!sql) {
      results.push({ query: name, status: "skipped", gotRows: 0, wantRows: want?.rows.length ?? 0, deltas: ["query text missing"] });
      continue;
    }
    if (!want) {
      results.push({ query: name, status: "skipped", gotRows: 0, wantRows: 0, deltas: ["no reference answer"] });
      continue;
    }
    const t0 = Date.now();
    try {
      const rows = runner.queryRows(sql, params[name] ?? {});
      const elapsed = Date.now() - t0;
      if (elapsed > QUERY_TIMEOUT_WARN_MS) {
        console.log(`[tpch_validate] ${name}: slow (${elapsed}ms)`);
      }
      const r = compareQueryResult(name, rows, want);
      results.push(r);
    } catch (e) {
      results.push({
        query: name,
        status: "error",
        gotRows: 0,
        wantRows: want.rows.length,
        deltas: [],
        errorMessage: (e as Error)?.message ?? String(e),
      });
    }
  }
  return results;
}

/** Pretty-print a comparison summary to stdout. */
export function logSummary(results: QueryCompareResult[]): void {
  let ok = 0;
  let mismatch = 0;
  let skipped = 0;
  let error = 0;
  const lines: string[] = [];
  lines.push("===== TPC-H query validation vs answers_sf1.json =====");
  for (const r of results) {
    switch (r.status) {
      case "ok":
        ok++;
        lines.push(
          `  ${r.query.padEnd(4)}: OK      rows=${r.gotRows} (want ${r.wantRows})`,
        );
        break;
      case "mismatch": {
        mismatch++;
        const preview = r.deltas.slice(0, 3).join("; ") + (r.deltas.length > 3 ? ` … (+${r.deltas.length - 3} more)` : "");
        lines.push(
          `  ${r.query.padEnd(4)}: DIFF    rows=${r.gotRows}/${r.wantRows}  ${preview}`,
        );
        break;
      }
      case "skipped":
        skipped++;
        lines.push(`  ${r.query.padEnd(4)}: SKIP    ${r.deltas.join("; ")}`);
        break;
      case "error":
        error++;
        lines.push(
          `  ${r.query.padEnd(4)}: ERROR   ${r.errorMessage ?? "(no message)"}`,
        );
        break;
    }
  }
  lines.push(
    `  total=${results.length}  ok=${ok}  diff=${mismatch}  skipped=${skipped}  error=${error}`,
  );
  console.log(lines.join("\n"));
}
